import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the input size to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input size exceeds limit. Please enter a name with maximum 10 characters.");
            return;
        }

        // Copying user input into the buffer with proper length check
        char[] buffer = new char[name.length()];
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Welcome, " + new String(buffer));
    }
}

### Explanation:
